{"path": "/tmp/sv-ea87bbbb4c2a45318c41c560c5af9372/Components/Board/KanbanColumn.razor", "file_text": "<div class="kanban-column">
    <div class="column-header">
        <h3>@ColumnName <span class="task-count">(@Tasks.Count)</span></h3>
    </div>

    <div class="column-body">
        @foreach (var task in Tasks)
        {
            <TaskCard Task="task"
                      ShowMoveLeft="ShowMoveLeft"
                      ShowMoveRight="ShowMoveRight"
                      OnMoveLeft="() => HandleMoveLeft(task)"
                      OnMoveRight="() => HandleMoveRight(task)" />
        }
    </div>

    @if (showAddForm)
    {
        <AddTaskForm Status="@Status"
                     OnTaskCreated="HandleTaskCreated"
                     OnCancel="() => showAddForm = false" />
    }
    else
    {
        <button class="btn-add" @onclick="() => showAddForm = true">+ Add Task</button>
    }
</div>

@code {
    [Parameter, EditorRequired] public required string ColumnName { get; set; }
    [Parameter, EditorRequired] public required string Status { get; set; }
    [Parameter, EditorRequired] public required List<Services.TaskItem> Tasks { get; set; }
    [Parameter] public bool ShowMoveLeft { get; set; }
    [Parameter] public bool ShowMoveRight { get; set; }
    [Parameter] public EventCallback<(int TaskId, string Direction)> OnTaskMoved { get; set; }
    [Parameter] public EventCallback<Services.TaskItem> OnTaskCreated { get; set; }

    private bool showAddForm;

    private async Task HandleMoveLeft(Services.TaskItem task)
    {
        await OnTaskMoved.InvokeAsync((task.Id, "left"));
    }

    private async Task HandleMoveRight(Services.TaskItem task)
    {
        await OnTaskMoved.InvokeAsync((task.Id, "right"));
    }

    private async Task HandleTaskCreated(Services.TaskItem task)
    {
        showAddForm = false;
        await OnTaskCreated.InvokeAsync(task);
    }
}
"}

