@@ -1,0 +1,75 @@
+<div class="add-task-form">
+    <div class="form-field">
+        <label>Title</label>
+        <input type="text" @bind="title" placeholder="Task title" />
+    </div>
+    <div class="form-field">
+        <label>Assignee</label>
+        <input type="text" @bind="assignee" placeholder="Assignee name" />
+    </div>
+    <div class="form-field">
+        <label>Priority</label>
+        <select @bind="priority">
+            <option value="High">High</option>
+            <option value="Medium">Medium</option>
+            <option value="Low">Low</option>
+        </select>
+    </div>
+    <div class="form-field">
+        <label>Due Date</label>
+        <input type="date" @bind="dueDate" />
+    </div>
+    <div class="form-actions">
+        <button class="btn-save" @onclick="HandleSave" disabled="@isSaving">
+            @(isSaving ? "Saving..." : "Save")
+        </button>
+        <button class="btn-cancel" @onclick="HandleCancel" disabled="@isSaving">Cancel</button>
+    </div>
+    @if (!string.IsNullOrEmpty(error))
+    {
+        <p class="form-error">@error</p>
+    }
+</div>
+
+@code {
+    [Parameter, EditorRequired] public EventCallback<Services.TaskItem> OnTaskCreated { get; set; }
+    [Parameter, EditorRequired] public EventCallback OnCancel { get; set; }
+    [Parameter, EditorRequired] public required string Status { get; set; }
+
+    private string title = "";
+    private string assignee = "";
+    private string priority = "Medium";
+    private DateTime dueDate = DateTime.Today.AddDays(7);
+    private bool isSaving;
+    private string? error;
+
+    [Inject] private Services.ITaskService TaskService { get; set; } = default!;
+
+    private async Task HandleSave()
+    {
+        if (string.IsNullOrWhiteSpace(title))
+        {
+            error = "Title is required.";
+            return;
+        }
+
+        error = null;
+        isSaving = true;
+        try
+        {
+            var created = await TaskService.CreateTaskAsync(title, assignee, priority, dueDate);
+            await OnTaskCreated.InvokeAsync(created);
+        }
+        catch (Exception ex)
+        {
+            error = $"Failed to create task: {ex.Message}";
+        }
+        finally
+        {
+            isSaving = false;
+        }
+    }
+
+    private async Task HandleCancel() => await OnCancel.InvokeAsync();
+}
+

