.add-task-form {
    background: #f9f9f9;
    border: 1px dashed #ccc;
    border-radius: 8px;
    padding: 12px;
    margin-top: 8px;
}

.form-field {
    margin-bottom: 8px;
}

.form-field label {
    display: block;
    font-size: 0.8rem;
    font-weight: 600;
    margin-bottom: 2px;
}

.form-field input,
.form-field select {
    width: 100%;
    padding: 6px 8px;
    border: 1px solid #ccc;
    border-radius: 4px;
    font-size: 0.85rem;
    box-sizing: border-box;
}

.form-actions {
    display: flex;
    gap: 8px;
    margin-top: 8px;
}

.btn-save {
    padding: 6px 14px;
    background: #3182ce;
    color: #fff;
    border: none;
    border-radius: 4px;
    cursor: pointer;
    font-size: 0.85rem;
}

.btn-save:hover:not(:disabled) {
    background: #2b6cb0;
}

.btn-save:disabled {
    opacity: 0.6;
    cursor: not-allowed;
}

.btn-cancel {
    padding: 6px 14px;
    background: #e2e8f0;
    border: none;
    border-radius: 4px;
    cursor: pointer;
    font-size: 0.85rem;
}

.btn-cancel:hover:not(:disabled) {
    background: #cbd5e0;
}

.form-error {
    color: #e53e3e;
    font-size: 0.8rem;
    margin-top: 6px;
