arguments.file_text:
@page "/board"
@using sv_ea87bbbb4c2a45318c41c560c5af9372.Components.Board
@rendermode InteractiveServer

<PageTitle>Kanban Board</PageTitle>

<h2>Kanban Board</h2>

@if (isLoading)
{
    <p><em>Loading tasks...</em></p>
}
else if (errorMessage is not null)
{
    <div class="error-banner">
        <p>@errorMessage</p>
        <button @onclick="LoadTasks">Retry</button>
    </div>
}
else
{
    <BoardStats Tasks="allTasks" />
    <BoardSearchBar SearchTerm="@searchTerm" OnSearchChanged="HandleSearchChanged" />

    <div class="board-columns">
        <KanbanColumn ColumnName="To Do" Status="To Do"
                      Tasks="GetFilteredTasks("To Do")"
                      ShowMoveLeft="false" ShowMoveRight="true"
                      OnTaskMoved="HandleTaskMoved"
                      OnTaskCreated="HandleTaskCreated" />

        <KanbanColumn ColumnName="In Progress" Status="In Progress"
                      Tasks="GetFilteredTasks("In Progress")"
                      ShowMoveLeft="true" ShowMoveRight="true"
                      OnTaskMoved="HandleTaskMoved"
                      OnTaskCreated="HandleTaskCreated" />

        <KanbanColumn ColumnName="Done" Status="Done"
                      Tasks="GetFilteredTasks("Done")"
                      ShowMoveLeft="true" ShowMoveRight="false"
                      OnTaskMoved="HandleTaskMoved"
                      OnTaskCreated="HandleTaskCreated" />
    </div>
}

@code {
    [Inject] private Services.ITaskService TaskService { get; set; } = default!;

    private List<Services.TaskItem> allTasks = new();
    private string searchTerm = "";
    private bool isLoading = true;
    private string? errorMessage;

    private static readonly string[] Statuses = ["To Do", "In Progress", "Done"];

    protected override async Task OnInitializedAsync()
    {
        await LoadTasks();
    }

    private async Task LoadTasks()
    {
        isLoading = true;
        errorMessage = null;
        try
        {
            allTasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to load tasks: {ex.Message}";
        }
        finally
        {
            isLoading = false;
        }
    }

    private List<Services.TaskItem> GetFilteredTasks(string status)
    {
        var tasks = allTasks.Where(t => t.Status == status);
        if (!string.IsNullOrWhiteSpace(searchTerm))
        {
            tasks = tasks.Where(t => t.Title.Contains(searchTerm, StringComparison.OrdinalIgnoreCase));
        }
        return tasks.ToList();
    }

    private void HandleSearchChanged(string value)
    {
        searchTerm = value;
    }

    private async Task HandleTaskMoved((int TaskId, string Direction) move)
    {
        var task = allTasks.FirstOrDefault(t => t.Id == move.TaskId);
        if (task is null) return;

        var currentIndex = Array.IndexOf(Statuses, task.Status);
        var newIndex = move.Direction == "left" ? currentIndex - 1 : currentIndex + 1;

        if (newIndex < 0 || newIndex >= Statuses.Length) return;

        var newStatus = Statuses[newIndex];
        try
        {
            await TaskService.UpdateTaskStatusAsync(task.Id, newStatus);
            var idx = allTasks.IndexOf(task);
            allTasks[idx] = task with { Status = newStatus };
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to move task: {ex.Message}";
        }
    }

    private void HandleTaskCreated(Services.TaskItem task)
    {
        allTasks.Add(task);
    }
}

.board-columns {
    display: flex;
    gap: 16px;
    align-items: flex-start;
}

.error-banner {
    background: #fed7d7;
    border: 1px solid #feb2b2;
    border-radius: 8px;
    padding: 12px 16px;
    color: #c53030;
    margin-bottom: 16px;
}

.error-banner button {
    margin-top: 8px;
    padding: 6px 14px;
    background: #c53030;
    color: #fff;
    border: none;
    border-radius: 4px;
    cursor: pointer;
}

@page "/board"
@using sv_ea87bbbb4c2a45318c41c560c5af9372.Components.Board
@rendermode InteractiveServer

<PageTitle>Kanban Board</PageTitle>

<h2>Kanban Board</h2>

@if (isLoading)
{
    <p><em>Loading tasks...</em></p>
}
else if (errorMessage is not null)
{
    <div class="error-banner">
        <p>@errorMessage</p>
        <button @onclick="LoadTasks">Retry</button>
    </div>
}
else
{
    <BoardStats Tasks="allTasks" />
    <BoardSearchBar SearchTerm="@searchTerm" OnSearchChanged="HandleSearchChanged" />

    <div class="board-columns">
        <KanbanColumn ColumnName="To Do" Status="To Do"
                      Tasks="GetFilteredTasks("To Do")"
                      ShowMoveLeft="false" ShowMoveRight="true"
                      OnTaskMoved="HandleTaskMoved"
                      OnTaskCreated="HandleTaskCreated" />

        <KanbanColumn ColumnName="In Progress" Status="In Progress"
                      Tasks="GetFilteredTasks("In Progress")"
